import{_ as t,o as i,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"109. Psychiatric Enrolled Nurse Classifications","description":"","frontmatter":{"title":"109. Psychiatric Enrolled Nurse Classifications","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/109-psychiatric-enrolled-nurse-classifications.md","filePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/109-psychiatric-enrolled-nurse-classifications.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/classification-staffing/109-psychiatric-enrolled-nurse-classifications.md"};function s(a,e,c,l,p,d){return i(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_109-psychiatric-enrolled-nurse-classifications" tabindex="-1">109. Psychiatric Enrolled Nurse Classifications <a class="header-anchor" href="#_109-psychiatric-enrolled-nurse-classifications" aria-label="Permalink to &quot;109. Psychiatric Enrolled Nurse Classifications&quot;">​</a></h1><p><strong>109.1</strong> Psychiatric Enrolled Nurses – features</p><p><strong>(a)</strong> A PEN is an enrolled nurse who works as part of the specialist mental health nursing team, under the supervision of an RPN. PENs work as a part of the mental health team to advocate for and facilitate the involvement of individuals, their families and significant others in planning and evaluating care and progress toward recovery and improved health outcomes. No consumer will be treated solely by a PEN.</p><p><strong>(b)</strong> Core PEN responsibilities in the provision of person-centred nursing care include recognition of normal and abnormal in assessment, intervention and evaluation of individual health and functional status. As well as the provision of support and comfort, assisting with activities of daily living to achieve an optimal level of independence, and providing for emotional needs of individuals with their aim being to ensure physical and psychological wellbeing and recovery of consumers. The PEN monitors the impact of nursing care and maintains ongoing communication with the registered nurse regarding the health and functional status of individuals.</p><p><strong>(c)</strong> PENs are deployed in a wide range of work settings. Services to each consumer will be determined by a team, which could include a RPN, or another qualified professional. They will perform a range of functions according to work setting, consumer needs and expertise of the PEN. Their aim is to ensure the physical and psychological well-being of their consumers in accordance with the legal and ethical requirements of the Mental Health Act 2014, or its successor.</p><p><strong>(d)</strong> The PEN knowledge and expertise in mental health nursing is advanced by the experience of working in the sector under supervision and mentorship and /or from post basic training.</p><p><strong>(e)</strong> Where the applicable law and organisational policy allows, enrolled nurses may administer prescribed medicines or maintain intravenous fluids, in accordance with their educational preparation.</p><p><strong>(f)</strong> At all times, the PEN retains responsibility for their actions and remains accountable in providing delegated nursing care. The enrolled nurse must maintain ongoing communication with the RPN including reporting changes in health and functional status and individual responses to health care interventions</p><p><strong>(g)</strong> The broad definitions of work at each level should be met by any individual position being classified at that level, subject to their educational preparation and consequential scope of practice. No single duty can be used as the basis on which to classify a job.</p><p><strong>109.2</strong> Psychiatric Enrolled Nurse Level 1 (PEN1)</p><p><strong>(a)</strong> Definition</p><p><strong>(i)</strong> At this Level a PEN works under the direct supervision and instruction of an RPN or a senior experienced PEN.</p><p><strong>(ii)</strong> A PEN 1 will be orientating to the roles and responsibilities within their working environment. PEN1 will undertake work as directed within established procedures and guidelines. They will be expected to develop their knowledge and understanding of their legal and ethical role under relevant legislation including the Mental Health Act 2014 or its successor.</p><p><strong>(iii)</strong> All newly graduated PEN commence at Level 1. A PEN graduating with a Diploma will commence at PEN Level 1 Year 7</p><p><strong>(iv)</strong> Progression – A PEN1 will progress through the increments on completion of a year of experience, including previous experience.</p><p><strong>(v)</strong> A PEN Level 1 will only progress to PEN2 classification if they meet the criteria set out for a PEN Level 2.</p><p><strong>(b)</strong> Typical PEN1 Duties</p><p><strong>(i)</strong> Organise and complete delegated nursing care of consumers.</p><p><strong>(ii)</strong> Encourage and support consumers to attain independence or assist consumers to maintain independence in daily living.</p><p><strong>(iii)</strong> Establish and maintain a rapport with consumers that will contribute their therapeutic treatment/activities.</p><p><strong>(iv)</strong> Record and report consumers progress in the clinical file and participate in handover of allocated consumers.</p><p><strong>(v)</strong> Assisting in routine admission procedures when a new consumer enters the unit</p><p><strong>(vi)</strong> Welcome consumers to the unit and orient them to unit routine. Explain unit routine to nominated family/friends of consumers.</p><p><strong>(vii)</strong> Under direction, carry out basic therapeutic or rehabilitative tasks with consumers, either individually or in groups.</p><p><strong>(viii)</strong> When requested by the nurse in charge, accompany consumers to appointments outside the unit or service.</p><p><strong>(ix)</strong> Act in emergency situations according to established procedures within the bounds of the PENs scope of practice.</p><p><strong>(x)</strong> Accurately record and label specimens, such as urine, perform urinalysis and report abnormalities.</p><p><strong>(xi)</strong> Assisting in the creation of safe, stable and therapeutic environments for consumers.</p><p><strong>(xii)</strong> Can only be rostered to HDU (howsoever titled) after completion of approved aggression management training and a minimum 6 months of experience in a mental health setting. A PEN 1 will not be the sole nurse in HDU and must be rostered with an experienced RPN.</p><p><strong>(xiii)</strong> Carry out clinical procedures for which training, supervision and level of competence has been achieved and recorded.</p><p><strong>(xiv)</strong> Maintain a high standard of documentation in accordance with level of competence.</p><p><strong>(xv)</strong> Contribute to quality improvement activities.</p><p><strong>(xvi)</strong> Ordering of medical supplies.</p><p><strong>109.3</strong> Psychiatric Enrolled Nurse Level 2 (PEN2)</p><p><strong>(a)</strong> Definition</p><p><strong>(i)</strong> A PEN 2 is an experienced PEN who works under the supervision of an RPN and will have an established understanding of the usual work and practices within the unit, a capacity to think critically, to analyse situations and act accordingly. They will generally practice with less direct supervision and take a more comprehensive approach to care, using a greater capacity for a critical approach to clinical assessment and management.</p><p><strong>(ii)</strong> They will be able to demonstrate an understanding of their own, consumer and environmental safety issues. They will have an established knowledge and understanding of, and work in accordance with their legal and ethical responsibilities under relevant legislation including the Mental Health Act 2014, or its successor.</p><p><strong>(b)</strong> PEN Level 2 applies to Enrolled Nurses who:</p><p><strong>(i)</strong> have at least 2 years&#39; experience and holds either an NMBA approved qualification in administration of medicines or a post registration qualification in mental health nursing; or</p><p><strong>(ii)</strong> performs duties at a PEN2 level; or</p><p><strong>(iii)</strong> are undertaking a Community Training Position of up to 12 months (as defined).</p><p><strong>(c)</strong> Progression - A PEN2 will progress through the increments on completion of a year of experience, including previous experience, as per <a href="/eba/ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.html">clause 70</a>.</p><p><strong>(d)</strong> There is no automatic progression for a PEN2 to the PEN3 classification.</p><p><strong>(e)</strong> Typical PEN2 Duties</p><p><strong>(i)</strong> Administration of prescribed medications inclusive of provision of information about the medication to consumers.</p><p><strong>(ii)</strong> Clinical observation and assessment of the effects of medication.</p><p><strong>(iii)</strong> Conduct mental state examinations.</p><p><strong>(iv)</strong> Conduct more comprehensive psychosocial assessments within scope of practise, including initial interviews of consumers.</p><p><strong>(v)</strong> Compile consumer history and presentation for the development of a person-centred care plan, however titled, and/or patient care strategies and identify clinical risks.</p><p><strong>(vi)</strong> Participate in consumer reviews and discharge planning, in collaboration with the consumer, carers, significant others and multidisciplinary team.</p><p><strong>(vii)</strong> Providing education to consumers, carer and significant others.</p><p><strong>(viii)</strong> Implement and evaluate activities for consumers (including group sessions), in consultation with a Registered Psychiatric Nurse or other qualified health professional.</p><p><strong>(ix)</strong> Maintain a safe, stable and therapeutic physical and psychosocial environment for consumers and staff.</p><p><strong>(x)</strong> Run, plan and develop basic therapeutic group activity sessions and/or social and community inclusion activities in consultation with the nurse educator/Shift Leader/ Allied Health Professional / Psychologists.</p><p><strong>(xi)</strong> Lead junior staff in the development and evaluation of specific programs, initiatives or research programs where appropriate and participation in quality improvement activities.</p><p><strong>(xii)</strong> May be rostered to HDU (howsoever titled), on the provision that approved aggression management training has been completed.</p><p><strong>(xiii)</strong> Having completed a preceptorship course, act as a mentor/preceptor to PEN students or MHOs when required.</p><p><strong>(xiv)</strong> Undertake &amp; participate in admission process including completion of admissions of consumers.</p><p><strong>109.4</strong> Psychiatric Enrolled Nurse Level 3 (PEN3)</p><p><strong>(a)</strong> Definition</p><p><strong>(i)</strong> A PEN 3 will practise at an advanced level within the Mental Health specialty and works under the direction of professional staff and an RPN. They will be expected to take a complex and critical approach to clinical care with an increased breadth and depth of knowledge and skills and exercise considerable judgement when analysing and responding to events or situations. They will have advanced knowledge and understanding of, and work in accordance with, their legal and ethical responsibilities under relevant legislation including the Mental Health Act 2014, or its successor.</p><p><strong>(ii)</strong> They may undertake roles in specific specialist domains such as Education, Quality and Liaison roles, including leadership. They may work in community settings, functioning independently within the scope of broad directions.</p><p><strong>(iii)</strong> PEN 3 applies to enrolled nurses who meet not less than two out of the three eligibility criteria below before making an application.</p><p><strong>(iv)</strong> Progression – A PEN3 will progress through the increments on completion of a year of experience, including previous experience, as per <a href="/eba/ebas/mental-health/rpn-pen-mho/preliminary/70-definitions-specific-to-section-2.html">clause 70</a>.</p><p><strong>(v)</strong> Community Mental Health – Despite any other criteria in this clause PEN3 is the minimum classification for enrolled nurses working in the community mental health setting, subject to the Community Training Provisions in <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.html">clause 101.11</a>.</p><p><strong>(b)</strong> Typical PEN3 Duties</p><p><strong>(i)</strong> Conduct mental state examination, psychosocial and community-based assessment.</p><p><strong>(ii)</strong> Monitor consumers’ physical and mental health status and provide appropriate intervention across a range of settings.</p><p><strong>(iii)</strong> Independently implement and evaluate person centred care plans in the community and inpatient settings, under the general supervision of an RPN.</p><p><strong>(iv)</strong> Participate in established processes for metabolic monitoring of consumers.</p><p><strong>(v)</strong> Provide psychoeducation to carers/families/services whenever appropriate.</p><p><strong>(vi)</strong> Prepare for consumer related case presentations/reviews and participate in clinical case conferences and other related meetings.</p><p><strong>(vii)</strong> Assist consumers/ carers to access appropriate support services within community settings.</p><p><strong>(viii)</strong> Liaison with and provide support to relevant health care providers and community services.</p><p><strong>(ix)</strong> Plan, promote, initiate, develop, run and conduct quality activities with relative independence.</p><p><strong>(x)</strong> Advanced knowledge of the Mental Health Act 2014, or its successor, and other relevant legislation.</p><p><strong>(xi)</strong> Having completed a preceptorship course, act as a preceptor to PENs, students, and MHOs and as a mentor to graduate RPNs.</p><p><strong>(xii)</strong> Undertake portfolio responsibilities.</p><p><strong>(xiii)</strong> Undertake community-based case work in accordance with plans and directions of the primary case manager.</p><p><strong>(c)</strong> For those PEN 3’s with NMBA approved medication endorsement:</p><p><strong>(i)</strong> Administration of prscribed medications (outreach may be required).</p><p><strong>(ii)</strong> In community-based service, assist with the co-ordination of the depot administering system, including maintenance of a depot data base.</p><p><strong>(d)</strong> The eligibility criteria are:</p><p><strong>(i)</strong> Can provide evidence of achievement of four out of the ten Advanced Enrolled Nurse Level 3 Competency Standards below; AND</p><p><strong>(ii)</strong> Either: <strong>(A)</strong> A minimum of five years post registration experience as a PEN OR <strong>(B)</strong> A post registration qualification a component of which is relevant to current environment/role.</p><p><strong>(e)</strong> Advanced PEN Level 3 Competency Standards The following are examples of competency standards that meet the eligibility criteria in sub-clause 109.4(d)(i) above.</p><p><strong>(i)</strong> Contributes to the education of new graduate PENs and/or Trainee PENs. For example, the Advanced PEN may precept or mentor new graduate Enrolled Nurses and/or Trainee Enrolled Nurses or contribute to the performance appraisal of less experienced PENs.</p><p><strong>(ii)</strong> The PEN may be involved in committees and working parties within and/or beyond the work unit</p><p><strong>(iii)</strong> Assists in the coordination of delegated activities of other staff under the guidance and direction of the RPN. For example, guides and supports activities of other PENs</p><p><strong>(iv)</strong> Act as a resource to others. For example, may take responsibility for a specific task, such as equipment maintenance schedules, rosters or stock control</p><p><strong>(v)</strong> Contributes to quality improvements within their work area or the workplace and/or changes in PEN practice initiatives. For example, identifies risks and potential outcomes during assessments or identifies and implements harm minimisation strategies</p><p><strong>(vi)</strong> Practises using specialised or advanced knowledge and skills in a clinical area within the enrolled nursing scope of practice. For example, applies acquired knowledge in child and family health care, recovery and rehabilitation, prevention of occupational violence and aggression, dementia care or other specific areas of clinical practice consistent with their educational preparation</p><p><strong>(vii)</strong> Modifies practice to accommodate consumer health care needs of individuals and groups in different environments. For example, contributes to the effective utilisation of nursing resources in the context of changing workloads or responds effectively to changes in clinical situations within scope of practice required</p><p><strong>(viii)</strong> Undertakes portfolio responsibilities either individually or as part of a clinical/quality team.</p><p><strong>(ix)</strong> Is aware of and functions in accordance with legislation, policies and procedures affecting PEN practice.</p><p><strong>(x)</strong> Actively participates in team leadership and decision making. Explanatory note: The parties recognise that additional opportunities may exist that are comparable in terms of skill or responsibility to those above. A lack of opportunity to meet sufficient standards is not to be used as a rationale for denying an Employee classification at PEN3.</p><p><strong>(f)</strong> Portability of PEN3 classification</p><p><strong>(i)</strong> A PEN3 classified at PEN3 shall be paid for all hours worked at the PEN3 classification and continue to be employed at Level 3 across the public sector including in the event they change Employer.</p><p><strong>(ii)</strong> Evidence required to demonstrate PEN3 to a new Employer shall be any one of the following: <strong>(A)</strong> Payslip; or <strong>(B)</strong> Certificate of Service; or <strong>(C)</strong> Letter of appointment.</p><p><strong>(g)</strong> Applications for Advancement to PEN 3 (existing Employees):</p><p><strong>(i)</strong> Application principles <strong>(A)</strong> The process for applications for PEN3 should ensure that applicants have equal opportunity to demonstrate their suitability <strong>(B)</strong> Applicants should have reasonable access to the same information relevant to the PEN3 criteria <strong>(C)</strong> No restrictions, other than the set eligibility requirements, are to apply <strong>(D)</strong> Potential applicants should be allowed reasonable time to prepare for the process.</p><p><strong>(ii)</strong> Application process <strong>(A)</strong> Applications may be made by a PEN when they believe they meet the eligibility criteria. Each Employer will arrange for the advertising of PEN3 classification once every six months. This information will be permanently available to PENs.</p><p><strong>(B)</strong> Written applications are to be made to the NUM (or equivalent position) <strong>(C)</strong> The written application must address the criteria in this Agreement, including: 1) evidence of achievement of four out of ten of the Advanced PEN 3 criteria; and 2) either:  A minimum of five years post registration experience as a PEN; OR  A post registration qualification (of at least 6 months or 200 hours duration) a component of which is relevant to current environment/role. <strong>(D)</strong> Interviews, if required: 1) Will be held within 10 days of the application. 2) Will be conducted by the NUM and may also include up to two other nursing staff such as the ANUM or Nurse Educator at the local level. 3) Must relate directly to the criteria in sub-clause 109.4(g)(ii)(C), and the supporting evidence within the application. <strong>(E)</strong> The PEN will be notified in writing of the outcome within 7 days of the receipt of the application, or where there is an interview, within 7 days after the interview. <strong>(F)</strong> For successful applicants, re-grading will apply from the date of application and be payable from the next fortnightly pay period after notification of a successful application. <strong>(G)</strong> If the application is unsuccessful, the Employer is to provide detailed written feedback aligned with the criteria, with a supportive development plan to be commenced to assist the PEN in any future application and meeting the eligibility criteria.</p><p><strong>109.5</strong> PEN Level 4 - Enrolled Nurse Education Support An experienced PEN who works with the registered nurse (RPN 4 – Psychiatric Clinical Nurse Educator and/or RPN 5 Psychiatric Nurse Consultant) as part of the Mental Health training and development team NMBA Enrolled Nurses Standards for Practice (2016) stipulate the need for the PEN to have a named and accessible Registered Psychiatric Nurse (RPN) at all times and in all contexts of care for support and guidance. The PEN 4 position is not a substitute for the RPN 4 Clinical Nurse Educator and RPN 5 Psychiatric Nurse Consultant Professional Development positions. It is desirable that the PEN 4 position has completed or is supported by the Employer to complete the Advanced Diploma Units of competency in Mental Health. Where an PEN 4 position has a Certificate IV in TAE, the relevant certificate allowance will be paid The PEN 4 position has a capability to:</p><p><strong>(a)</strong> Provide competent person-centred care,</p><p><strong>(b)</strong> Engage in reflective and analytical practice and</p><p><strong>(c)</strong> Contributes to the learning and development of new graduate Enrolled Nurses and/or trainee enrolled nurses and other (unregulated) health care workers At 1 July 2020, each of the three Mental Health training and development Clusters via the Centre of Mental Health Learning, were allocated one EFT of a PEN 4 Enrolled Nurse Education Support position. Typical duties</p><p><strong>(i)</strong> Under the broad direction of the Registered Psychiatric Nurse (RPN 4 or 5) is a resource for information on mental health and nursing matters within the PEN scope of practice,</p><p><strong>(ii)</strong> Undertake a range of practice development initiatives in residential and acute program settings to build PEN practice and improve outcomes for consumers</p><p><strong>(iii)</strong> Assist the CNE (RPN 4) to provide support to undergraduate Diploma of Nursing Students on clinical placement</p><p><strong>(iv)</strong> Provide preceptorship to students undertaking the Diploma of Nursing, after they have completed Preceptorship training</p><p><strong>(v)</strong> Participate in the orientation for PENs, MHOs and LEWs</p><p><strong>(vi)</strong> Assist Registered Psychiatric Nurses (RPN 4 and RPN 5) to provide skill refreshment activities to other PENs</p><p><strong>(vii)</strong> Promotes the safety of self and others in all aspects of nursing care</p><p><strong>(viii)</strong> Provide advice to the Senior Psychiatric Nurses on specific PEN workforce issues</p><p><strong>(ix)</strong> Represent PENs at State-wide Professional Development forum.</p><p><strong>109.6</strong> Translation (all PEN Levels)</p><p><strong>(a)</strong> The following translation has occurred and will continue to apply:</p><p>Current No Meds plus meds Plus Senior plus both PSEN 1 Year 1 PEN 1.1 PEN 1.5 Year 2 PEN 1.2 PEN 1.6 Year 3 PEN 1.3 PEN 2.1 Year 4 PEN 1.4 PEN 2.1 Year 5 PEN 1.6 PEN 2.1 Year 6 PEN 1.6 PEN 2.1 PEN 3.1 PEN 3.1 Year 7 PEN 1.7 PEN 2.1 PEN 3.1 PEN 3.2 Year 8 PEN 1.8 PEN 2.2 PEN 3.1 PEN 3.3 PSEN 2 Year 1 PEN 1.8 PEN 2.2 PEN 3.1 PEN 3.3 Year 2 PEN 2.1 PEN 2.4 PEN 3.2 PEN 3.3 Year 3 PEN 2.2 PEN 2.4 PEN 3.2 PEN 3.4#</p><p><strong>(b)</strong> PEN3.4 available only to existing PSEN2 y3 Employees in receipt of medication endorsement allowance and senior allowance as at 31 March 2012. These</p><p>Employees translate to the PEN3.4 as a result of the implementation of this Agreement. The PEN3.4 rate cannot be accessed through incremental progression.</p>',121)])])}const u=t(r,[["render",s]]);export{h as __pageData,u as default};
